export const r = String.raw; // Python-style raw strings
export function id(x) {
    return x;
}
export function not(f) {
    return x => !f(x);
}
export function fromMaybeUndefined(fallback, x) {
    return x === undefined ? fallback : x;
}
export function isEmpty(x) {
    return x === "";
}
export function containsWhitespace(x) {
    return /\s/.test(x);
}
export function containsOnlyWhitespace(x) {
    return /^\s*$/.test(x);
}
export function containsLeadingWhitespace(x) {
    return /^\s/.test(x);
}
export function containsTrailingWhitespace(x) {
    return /\s$/.test(x);
}
export function containsLineBreaks(x) {
    return x.includes("\n");
}
export function replaceHyphens(s) {
    return s.replace(/\-/g, "_");
}
export function replaceUnderscores(s) {
    return s.replace(/_/g, "-");
}
